sql:
SELECT conference_id, conference_name, conference_abbreviation
FROM conferences
WHERE conference_id > 0;

SELECT COUNT(*) 
FROM player_games 
WHERE player_id = 1;

SELECT player_id, plus_minus
FROM player_stats
WHERE plus_minus = (SELECT MAX(plus_minus) FROM player_stats);

SELECT DISTINCT playoff_champion
FROM seasons
WHERE playoff_champion IS NOT NULL;

SELECT DISTINCT team_name
FROM teams
WHERE division = 'Central' AND conference = 'NHL';

external_knowledge:
- A week's worth of games is considered more than 5 games missed;
- The Eastern conference includes various teams competing in the NBA or NFL;
- "Early October to early November" is precisely defined as between '2022-10-01' and '2022-11-01'.
